class Student {
private:
 string name;
 int rollNo;
 float marks;

public:
 // Constructor
 Student() {
 name = "";
 rollNo = 0;
 marks = 0.0;
 }

 // Parameterized Constructor
 Student(string n, int r, float m) {
 name = n;
 rollNo = r;
 marks = m;
 }

 // Member function to display
 void display() {
 cout << "Name: " << name << endl;
 cout << "Roll No: " << rollNo << endl;
 cout << "Marks: " << marks << endl;
 }
};

int main() {
 Student s1("John", 101, 85.5);
 s1.display();
 return 0;
}

class Box {
private:
 int length, breadth, height;

public:
 // Parameterized Constructor
 Box(int l, int b, int h) {
 length = l;
 breadth = b;
 height = h;
 }

 // Copy Constructor
 Box(const Box& b) {
 length = b.length;
 breadth = b.breadth;
 height = b.height;
 }

 int volume() {
 return length * breadth * height;
 }
};

int main() {
 Box b1(10, 20, 30);
 Box b2 = b1; // Copy constructor called
 Box b3(b1); // Another way
 cout << "Volume: " << b2.volume() << endl;
 return 0;
}

class Counter {
private:
 int count; // Instance variable
 static int objCount; // Static variable (shared)

public:
 Counter() {
 count = 0;
 objCount++;
 }

 // Static member function
 static int getObjectCount() {
 // Can only access static members
 // count++; // Error! Cannot access
 return objCount;
 }

 void increment() {
 count++;
 }

 void display() {
 cout << "Count: " << count << endl;
 }
};

// Initialize static member
int Counter::objCount = 0;

int main() {
 Counter c1, c2, c3;
 cout << "Objects created: " << Counter::getObjectCount() << endl;
 return 0;
}

class Box {
private:
 int length, breadth;

public:
 Box(int l, int b) {
 length = l;
 breadth = b;
 }

 // Declare friend function
 friend int calculateArea(Box b);
};

// Friend function definition (not a member)
int calculateArea(Box b) {
 // Can access private members directly
 return b.length * b.breadth;
}

int main() {
 Box b(10, 20);
 cout << "Area: " << calculateArea(b) << endl;
 return 0;
}

class Student {
private:
 string name;
 int marks;

public:
 Student(string n, int m) {
 name = n;
 marks = m;
 }

 // Const member function - cannot modify data members
 void display() const {
 cout << "Name: " << name << endl;
 cout << "Marks: " << marks << endl;
 // marks = 100; // Error! Cannot modify
 }

 // Non-const function can modify
 void updateMarks(int m) {
 marks = m;
 }
};

int main() {
 const Student s("John", 85); // Constant object
 s.display(); // Can only call const functions
 return 0;
}
